            --text-primary: #000000;
            --text-secondary: #666666;
            --text-muted: #999999;

            --tesla-red: #CC0000;
            --tesla-red-hover: #AA0000;
            --tesla-red-glow: rgba\(204, 0, 0, 0.2\);

            --accent: #CC0000;
            --accent-hover: #AA0000;
            --accent-glow: rgba\(204, 0, 0, 0.15\);

            --border: #E0E0E0;
            --shadow-sm: 0 2px 8px rgba\(0, 0, 0, 0.1\);
            --shadow-md: 0 4px 16px rgba\(0, 0, 0, 0.12\);
