            z-index: 1000;
        }

        .ai-chat-button:hover {
            transform: scale\(1.1\);
            box-shadow: 0 6px 30px var\(--tesla-red-glow-intense\);
        }

        .ai-chat-modal {
            display: none;
            position: fixed;
            bottom: 100px;
            right: 2rem;
            width: 400px;
            max-width: calc\(100vw - 4rem\);
            height: 600px;
            max-height: calc\(100vh - 150px\);
            background: var\(--bg-card\);
            border: 1px solid var\(--border\);
            border-radius: 16px;
            box-shadow: 0 10px 50px rgba\(0, 0, 0, 0.9\);
            z-index: 1001;
            flex-direction: column;
        }

        .ai-chat-modal.active {
            display: flex;
        }

        .ai-chat-header {
            padding: 1.25rem;
            border-bottom: 1px solid var\(--border\);
            display: flex;
            justify-content: space-between;
            align-items: center;
        }

        .ai-chat-title {
            font-weight: 700;
            font-size: 1.1rem;
        }

        .ai-chat-close {
            background: none;
            border: none;
            color: var\(--text-secondary\);
            font-size: 1.5rem;
            cursor: pointer;
            padding: 0;
            width: 30px;
            height: 30px;
            display: flex;
            align-items: center;
            justify-content: center;
            border-radius: 4px;
            transition: all 0.2s;
        }

        .ai-chat-close:hover {
            background: var\(--bg-hover\);
            color: var\(--text-primary\);
        }

        .ai-chat-messages {
            flex: 1;
            overflow-y: auto;
            padding: 1rem;
            display: flex;
            flex-direction: column;
            gap: 1rem;
        }

        .ai-message {
            padding: 0.75rem 1rem;
            border-radius: 12px;
            max-width: 85%;
        }

        .ai-message.user {
            align-self: flex-end;
            background: var\(--tesla-red\);
            color: white;
        }

        .ai-message.assistant {
            align-self: flex-start;
            background: var\(--bg-hover\);
            color: var\(--text-primary\);
        }

        .ai-message.error {
            align-self: flex-start;
            background: rgba\(239, 68, 68, 0.1\);
            color: #ef4444;
            border: 1px solid rgba\(239, 68, 68, 0.3\);
        }

        .ai-chat-input-container {
            padding: 1rem;
            border-top: 1px solid var\(--border\);
        }

        .ai-chat-input {
            width: 100%;
            padding: 0.75rem 1rem;
            border: 1px solid var\(--border\);
            border-radius: 8px;
            background: var\(--bg-dark\);
            color: var\(--text-primary\);
            font-family: inherit;
            resize: none;
        }

        .ai-chat-input:focus {
            outline: none;
            border-color: var\(--tesla-red\);
            box-shadow: 0 0 8px var\(--tesla-red-glow\);
        }

        .ai-typing {
            padding: 0.75rem 1rem;
            border-radius: 12px;
            background: var\(--bg-hover\);
            color: var\(--text-secondary\);
            align-self: flex-start;
            font-style: italic;
        }

        .ai-settings-gear {
            background: none;
            border: none;
            color: var\(--text-secondary\);
            font-size: 1.1rem;
            cursor: pointer;
            padding: 0;
            width: 30px;
            height: 30px;
            display: flex;
            align-items: center;
            justify-content: center;
            border-radius: 4px;
            transition: all 0.2s;
        }

        .ai-settings-gear:hover {
            background: var\(--bg-hover\);
            color: var\(--text-primary\);
        }

        .exclude-author-btn {
            padding: 0.2rem 0.5rem;
            font-size: 0.7rem;
            border: 1px solid rgba\(239, 68, 68, 0.4\);
            background: transparent;
            color: #ef4444;
            border-radius: 4px;
            cursor: pointer;
            transition: all 0.2s;
            margin-left: 0.5rem;
        }

        .exclude-author-btn:hover {
            background: rgba\(239, 68, 68, 0.15\);
        }

        /* ============================================
           STATES - Tesla Style
           ============================================ */
        .loading {
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            padding: 4rem 2rem;
            color: var\(--text-secondary\);
        }

        .spinner {
            width: 40px;
            height: 40px;
            border: 3px solid var\(--border\);
            border-top-color: var\(--tesla-red\);
            border-radius: 50%;
            animation: spin 1s linear infinite;
            margin-bottom: 1rem;
        }

        @keyframes spin {
            to { transform: rotate\(360deg\); }
        }

        .empty-state, .error-state {
            text-align: center;
            padding: 4rem 2rem;
            color: var\(--text-secondary\);
        }

        .empty-icon {
            font-size: 4rem;
            margin-bottom: 1rem;
            opacity: 0.5;
        }

        .empty-state h3, .error-state h3 {
            font-size: 1.25rem;
            color: var\(--text-primary\);
            margin-bottom: 0.5rem;
            font-weight: 700;
        }

        .initial-state {
            text-align: center;
            padding: 4rem 2rem;
        }

        .initial-state h3 {
            font-family: 'Inter', sans-serif;
            font-size: 1.5rem;
            font-weight: 700;
            color: var\(--text-primary\);
            margin-bottom: 1rem;
        }

        .search-tips {
            text-align: left;
            max-width: 400px;
            margin: 2rem auto 0;
            background: var\(--bg-card\);
            border: 1px solid var\(--border\);
            border-radius: 12px;
            padding: 1.25rem;
        }

        .search-tips h4 {
            font-size: 0.85rem;
            color: var\(--text-secondary\);
            margin-bottom: 0.75rem;
            text-transform: uppercase;
            letter-spacing: 0.1em;
            font-weight: 700;
        }

        .search-tips ul {
            list-style: none;
            font-size: 0.9rem;
            color: var\(--text-secondary\);
        }

        .search-tips li {
            padding: 0.4rem 0;
        }

        .search-tips code {
            background: var\(--bg-dark\);
            padding: 0.2rem 0.4rem;
            border-radius: 4px;
            font-size: 0.85rem;
            color: var\(--tesla-red\);
            font-weight: 600;
        }

        /* ============================================
           PAGINATION - Tesla Style
           ============================================ */
        .pagination {
            display: flex;
            justify-content: center;
            gap: 0.5rem;
            margin-top: 2rem;
        }

        .pagination button {
            padding: 0.6rem 1.2rem;
            font-size: 0.9rem;
            background: var\(--bg-card\);
            border: 1px solid var\(--border\);
            border-radius: 8px;
            color: var\(--text-primary\);
            cursor: pointer;
            transition: all 0.2s;
            font-family: inherit;
            font-weight: 700;
        }

        .pagination button:hover:not\(:disabled\) {
            border-color: var\(--tesla-red\);
            color: var\(--tesla-red\);
            box-shadow: 0 0 12px var\(--tesla-red-glow\);
        }

        .pagination button:disabled {
            opacity: 0.4;
            cursor: not-allowed;
        }

        .page-info {
            padding: 0.6rem 1.2rem;
            color: var\(--text-secondary\);
            font-weight: 600;
        }

        /* ============================================
           MODALS - Tesla Style
           ============================================ */
        .modal-overlay {
            position: fixed;
            top: 0;
            left: 0;
            right: 0;
            bottom: 0;
            background: rgba\(0, 0, 0, 0.85\);
            display: flex;
            align-items: center;
            justify-content: center;
            z-index: 2000;
            opacity: 0;
            visibility: hidden;
            transition: all 0.2s ease;
        }

        .modal-overlay.active {
            opacity: 1;
            visibility: visible;
        }

        .modal {
            background: var\(--bg-card\);
            border: 1px solid var\(--border\);
            border-radius: 16px;
            padding: 2rem;
            width: 90%;
            max-width: 450px;
            transform: translateY\(20px\);
            transition: transform 0.2s ease;
            box-shadow: var\(--shadow-lg\);
        }

        .modal-large .modal {
            max-width: 700px;
            max-height: 80vh;
            overflow-y: auto;
        }

        .modal-overlay.active .modal {
            transform: translateY\(0\);
        }

        .modal-title {
            font-size: 1.25rem;
            font-weight: 700;
            margin-bottom: 0.5rem;
            color: var\(--text-primary\);
        }

        .modal-subtitle {
            font-size: 0.9rem;
            color: var\(--text-secondary\);
            margin-bottom: 1.5rem;
        }

        .modal-form {
            display: flex;
            flex-direction: column;
            gap: 1rem;
        }

        .form-group {
            display: flex;
            flex-direction: column;
            gap: 0.5rem;
        }

        .form-group label {
            font-size: 0.85rem;
            color: var\(--text-secondary\);
            font-weight: 600;
        }

        .form-group input,
        .form-group select {
            padding: 0.75rem 1rem;
            font-size: 0.95rem;
            border: 1px solid var\(--border\);
            border-radius: 8px;
            background: var\(--bg-dark\);
            color: var\(--text-primary\);
            font-family: inherit;
        }

        .form-group input:focus,
        .form-group select:focus {
            outline: none;
            border-color: var\(--tesla-red\);
            box-shadow: 0 0 8px var\(--tesla-red-glow\);
        }

        .modal-actions {
            display: flex;
            gap: 0.75rem;
            margin-top: 1rem;
        }

        .modal-btn {
            flex: 1;
            padding: 0.75rem 1rem;
            font-size: 0.95rem;
            font-weight: 700;
            border-radius: 8px;
            cursor: pointer;
            transition: all 0.2s;
            font-family: inherit;
        }

        .modal-btn-secondary {
            background: transparent;
            border: 1px solid var\(--border\);
            color: var\(--text-secondary\);
        }

        .modal-btn-secondary:hover {
            border-color: var\(--text-secondary\);
            color: var\(--text-primary\);
        }

        .modal-btn-primary {
            background: var\(--tesla-red\);
            border: none;
            color: white;
        }

        .modal-btn-primary:hover {
            background: var\(--tesla-red-hover\);
            box-shadow: 0 0 16px var\(--tesla-red-glow\);
        }

        .modal-btn-primary:disabled {
            opacity: 0.5;
            cursor: not-allowed;
        }

        .modal-success {
            text-align: center;
            padding: 1rem 0;
        }

        .modal-success-icon {
            font-size: 3rem;
            margin-bottom: 1rem;
        }

        /* Admin Panel Tabs */
        .admin-tabs {
            display: flex;
            gap: 0.5rem;
            margin-bottom: 1.5rem;
            border-bottom: 1px solid var\(--border\);
        }

        .tab-btn {
            padding: 0.75rem 1.25rem;
            background: transparent;
            border: none;
            color: var\(--text-secondary\);
            cursor: pointer;
            font-family: inherit;
            font-size: 0.95rem;
            font-weight: 600;
            border-bottom: 2px solid transparent;
            transition: all 0.2s;
        }

        .tab-btn.active {
            color: var\(--tesla-red\);
            border-bottom-color: var\(--tesla-red\);
        }

        .tab-btn:hover {
            color: var\(--text-primary\);
        }

        .user-card {
            background: var\(--bg-card\);
            border: 1px solid var\(--border\);
            padding: 1rem;
            border-radius: 8px;
            margin-bottom: 1rem;
        }

        .user-card-header {
            display: flex;
            justify-content: space-between;
            align-items: flex-start;
            margin-bottom: 0.5rem;
        }

        .user-info {
            flex: 1;
        }

        .user-name {
            font-weight: 700;
            color: var\(--text-primary\);
            margin-bottom: 0.25rem;
        }

        .user-email {
            color: var\(--text-secondary\);
            font-size: 0.9rem;
        }

        .user-meta {
            color: var\(--text-muted\);
            font-size: 0.85rem;
            margin-top: 0.5rem;
        }

        /* Agent Settings Tabs */
        .agent-settings-tabs {
            display: flex;
            gap: 0;
            border-bottom: 1px solid var\(--border\);
            margin-bottom: 1.25rem;
        }

        .agent-tab-btn {
            padding: 0.75rem 1.25rem;
            background: transparent;
            border: none;
            color: var\(--text-secondary\);
            cursor: pointer;
            font-family: inherit;
            font-size: 0.9rem;
            font-weight: 600;
            border-bottom: 2px solid transparent;
            transition: all 0.2s;
        }

        .agent-tab-btn.active {
            color: var\(--tesla-red\);
            border-bottom-color: var\(--tesla-red\);
        }

        .agent-tab-btn:hover {
            color: var\(--text-primary\);
        }

        .agent-tab-content {
            display: none;
        }

        .agent-tab-content.active {
            display: block;
        }

        .exclusion-section {
            margin-bottom: 1.25rem;
        }

        .exclusion-section h4 {
            font-size: 0.9rem;
            color: var\(--text-secondary\);
            margin-bottom: 0.5rem;
            font-weight: 700;
        }

        .exclusion-tags {
            display: flex;
            flex-wrap: wrap;
            gap: 0.4rem;
            margin-bottom: 0.5rem;
            min-height: 28px;
            position: relative;
            transition: max-height 0.3s ease;
        }

        .exclusion-tags.collapsed {
            max-height: 60px;
            overflow: hidden;
            position: relative;
        }

        .exclusion-tags.collapsed::after {
            content: '';
            position: absolute;
            bottom: 0;
            left: 0;
            right: 0;
            height: 30px;
            background: linear-gradient\(to bottom, transparent, var\(--bg-secondary\)\);
            pointer-events: none;
        }

        .exclusion-toggle {
            margin-top: 0.5rem;
            padding: 0.3rem 0.6rem;
            font-size: 0.75rem;
            color: var\(--tesla-red\);
            background: transparent;
            border: 1px solid var\(--tesla-red\);
            border-radius: 4px;
            cursor: pointer;
            transition: all 0.2s;
            font-weight: 600;
        }

        .exclusion-toggle:hover {
            background: rgba\(204, 0, 0, 0.1\);
        }

        .exclusion-count {
            font-size: 0.75rem;
            color: var\(--text-muted\);
            margin-left: 0.5rem;
            font-style: italic;
        }

        .exclusion-tag {
            display: inline-flex;
            align-items: center;
            gap: 0.35rem;
            padding: 0.3rem 0.6rem;
            background: rgba\(204, 0, 0, 0.15\);
            border: 1px solid rgba\(204, 0, 0, 0.3\);
            border-radius: 16px;
            font-size: 0.8rem;
            color: var\(--text-primary\);
        }

        .exclusion-tag .remove-tag {
            cursor: pointer;
            color: var\(--text-muted\);
            font-size: 1rem;
            line-height: 1;
            transition: color 0.2s;
        }

        .exclusion-tag .remove-tag:hover {
            color: #ef4444;
        }

        .exclusion-add {
            display: flex;
            gap: 0.4rem;
        }

        .exclusion-add input {
            flex: 1;
            padding: 0.4rem 0.6rem;
            font-size: 0.85rem;
            border: 1px solid var\(--border\);
            border-radius: 6px;
            background: var\(--bg-dark\);
            color: var\(--text-primary\);
            font-family: inherit;
        }

        .exclusion-add input:focus {
            outline: none;
            border-color: var\(--tesla-red\);
        }

        .exclusion-add button {
            padding: 0.4rem 0.75rem;
            font-size: 0.85rem;
            border: 1px solid var\(--tesla-red\);
            background: transparent;
            color: var\(--tesla-red\);
            border-radius: 6px;
            cursor: pointer;
            font-family: inherit;
            font-weight: 600;
            transition: all 0.2s;
        }

        .exclusion-add button:hover {
            background: var\(--tesla-red\);
            color: white;
        }

        .defaults-grid {
            display: grid;
            gap: 1rem;
        }

        .defaults-grid .form-group label {
            display: block;
            font-size: 0.9rem;
            color: var\(--text-secondary\);
            margin-bottom: 0.4rem;
        }

        .defaults-grid .form-group input,
        .defaults-grid .form-group select {
            width: 100%;
            padding: 0.5rem 0.75rem;
            border: 1px solid var\(--border\);
            border-radius: 6px;
            background: var\(--bg-dark\);
            color: var\(--text-primary\);
            font-family: inherit;
            font-size: 0.9rem;
        }

        .defaults-grid .form-group input:focus,
        .defaults-grid .form-group select:focus {
            outline: none;
            border-color: var\(--tesla-red\);
        }

        .conference-checkboxes {
            display: flex;
            flex-wrap: wrap;
            gap: 0.5rem;
        }

        .conference-checkboxes label {
            display: flex;
            align-items: center;
            gap: 0.3rem;
            font-size: 0.85rem;
            color: var\(--text-primary\);
            cursor: pointer;
        }

        .agent-instructions-textarea {
            width: 100%;
            min-height: 120px;
            padding: 0.75rem;
            border: 1px solid var\(--border\);
            border-radius: 8px;
            background: var\(--bg-dark\);
            color: var\(--text-primary\);
            font-family: inherit;
            font-size: 0.9rem;
            resize: vertical;
        }

        .agent-instructions-textarea:focus {
            outline: none;
            border-color: var\(--tesla-red\);
        }

        .history-list {
            max-height: 400px;
            overflow-y: auto;
            display: flex;
            flex-direction: column;
            gap: 0.5rem;
        }

        .history-entry {
            padding: 0.6rem 0.75rem;
            border-radius: 8px;
            font-size: 0.85rem;
        }

        .history-entry.user {
            background: rgba\(204, 0, 0, 0.15\);
            align-self: flex-end;
            max-width: 85%;
        }

        .history-entry.assistant {
            background: var\(--bg-hover\);
            align-self: flex-start;
            max-width: 85%;
        }

        .history-entry .history-time {
            font-size: 0.7rem;
            color: var\(--text-muted\);
            margin-top: 0.25rem;
        }

        .history-empty {
            text-align: center;
            color: var\(--text-muted\);
            padding: 2rem;
            font-style: italic;
        }

        /* Author Profile Page */
        .author-profile {
            display: none;
        }

        .author-profile.active {
            display: block;
        }

        .back-btn {
            display: inline-flex;
            align-items: center;
            gap: 0.5rem;
            padding: 0.5rem 1rem;
            font-size: 0.9rem;
            background: transparent;
            border: 1px solid var\(--border\);
            border-radius: 8px;
            color: var\(--text-secondary\);
            cursor: pointer;
            margin-bottom: 1.5rem;
            transition: all 0.2s;
            font-family: inherit;
            font-weight: 600;
        }

        .back-btn:hover {
            border-color: var\(--tesla-red\);
            color: var\(--tesla-red\);
        }

        .profile-header {
            background: var\(--bg-card\);
            border: 1px solid var\(--border\);
            border-radius: 16px;
            padding: 2rem;
            margin-bottom: 1.5rem;
            box-shadow: var\(--shadow-md\);
        }

        .profile-name {
            font-family: 'Inter', sans-serif;
            font-size: 2rem;
            font-weight: 800;
            color: var\(--text-primary\);
            margin-bottom: 0.5rem;
        }

        .profile-affiliation {
            color: var\(--text-secondary\);
            font-size: 1rem;
            margin-bottom: 1rem;
        }

        .profile-links {
            display: flex;
            flex-wrap: wrap;
            gap: 0.5rem;
            margin-bottom: 1.5rem;
        }

        .profile-link {
            display: inline-flex;
            align-items: center;
            gap: 0.4rem;
            padding: 0.5rem 1rem;
            font-size: 0.85rem;
            font-weight: 600;
            border-radius: 8px;
            text-decoration: none;
            transition: all 0.2s;
        }

        .profile-link:hover {
            transform: translateY\(-2px\);
            filter: brightness\(1.2\);
        }

        .profile-link.homepage { background: rgba\(16, 185, 129, 0.15\); color: var\(--link-homepage\); }
        .profile-link.scholar { background: rgba\(66, 133, 244, 0.15\); color: var\(--link-scholar\); }
        .profile-link.dblp { background: rgba\(0, 79, 159, 0.15\); color: var\(--link-dblp\); }
        .profile-link.linkedin { background: rgba\(10, 102, 194, 0.15\); color: var\(--link-linkedin\); }
        .profile-link.orcid { background: rgba\(166, 206, 57, 0.15\); color: var\(--link-orcid\); }

        .profile-stats {
            display: grid;
            grid-template-columns: repeat\(auto-fit, minmax\(140px, 1fr\)\);
            gap: 1rem;
        }

        .stat-card {
            background: var\(--bg-dark\);
            border: 1px solid var\(--border\);
            border-radius: 10px;
            padding: 1rem;
            text-align: center;
        }

        .stat-card .stat-number {
            font-size: 1.75rem;
            font-weight: 800;
            color: var\(--tesla-red\);
        }

        .stat-card .stat-label {
            font-size: 0.8rem;
            color: var\(--text-muted\);
            text-transform: uppercase;
            letter-spacing: 0.05em;
            font-weight: 600;
        }

        .profile-section {
            background: var\(--bg-card\);
            border: 1px solid var\(--border\);
            border-radius: 12px;
            padding: 1.5rem;
            margin-bottom: 1rem;
            box-shadow: var\(--shadow-sm\);
        }

        .section-title {
            font-size: 1rem;
            font-weight: 700;
            color: var\(--text-primary\);
            margin-bottom: 1rem;
            display: flex;
            justify-content: space-between;
            align-items: center;
        }

        .export-btn {
            padding: 0.5rem 1rem;
            font-size: 0.8rem;
            background: var\(--tesla-red\);
            border: none;
            border-radius: 6px;
            color: white;
            cursor: pointer;
            font-family: inherit;
            font-weight: 700;
            transition: all 0.2s;
        }

        .export-btn:hover {
            background: var\(--tesla-red-hover\);
            box-shadow: 0 0 12px var\(--tesla-red-glow\);
        }

        .coauthor-list {
            display: flex;
            flex-wrap: wrap;
            gap: 0.5rem;
        }

        .coauthor-tag {
            padding: 0.4rem 0.8rem;
            background: var\(--bg-dark\);
            border: 1px solid var\(--border\);
            border-radius: 20px;
            font-size: 0.85rem;
            color: var\(--text-secondary\);
            cursor: pointer;
            transition: all 0.2s;
            font-weight: 600;
        }

        .coauthor-tag:hover {
            border-color: var\(--tesla-red\);
            color: var\(--tesla-red\);
        }

        .coauthor-tag .count {
            color: var\(--text-muted\);
            font-size: 0.75rem;
            margin-left: 0.3rem;
        }

